// pubspec: flutter_appauth: ^6.0.0
import 'package:flutter_appauth/flutter_appauth.dart';

final _appAuth = const FlutterAppAuth();
const _clientId = 'mobile-client-id';
const _redirect = 'com.example.app:/oauthredirect';
const _issuer   = 'https://auth.example.com';

Future<TokenSet> signIn() async {
  // flutter_appauth handles PKCE end-to-end:
  // - generates verifier+challenge
  // - opens system browser
  // - exchanges code for tokens
  final result = await _appAuth.authorizeAndExchangeCode(
    AuthorizationTokenRequest(
      _clientId,
      _redirect,
      issuer: _issuer,
      scopes: ['openid', 'profile', 'offline_access'],
      promptValues: const ['login'],
      // ✅ system browser, never WebView
      preferEphemeralSession: true,  // iOS: session not shared with Safari
    ),
  );
  return TokenSet(
    access:  result!.accessToken!,
    refresh: result.refreshToken,
    expiry:  result.accessTokenExpirationDateTime!,
  );
}

// Manual PKCE — when you can't use flutter_appauth
String _generateVerifier() {
  final rand = Random.secure();
  final bytes = List<int>.generate(32, (_) => rand.nextInt(256));
  return base64UrlEncode(bytes).replaceAll('=', '');
}
