// pubspec: flutter_jailbreak_detection: ^1.10.0
import 'package:flutter_jailbreak_detection/flutter_jailbreak_detection.dart';

class DeviceTrust {
  Future<TrustLevel> check() async {
    final results = await Future.wait([
      FlutterJailbreakDetection.jailbroken,
      FlutterJailbreakDetection.developerMode,
    ]);
    final jailbroken = results[0];
    final devMode    = results[1];

    if (jailbroken) return TrustLevel.compromised;
    if (devMode)    return TrustLevel.degraded;
    return TrustLevel.normal;
  }
}

// Tier the response — do not just block
Future<void> startup() async {
  final trust = await DeviceTrust().check();
  switch (trust) {
    case TrustLevel.normal:
      runApp(const App());
      break;
    case TrustLevel.degraded:
      // Disable biometric quick-unlock; force password every session
      runApp(const App(allowBiometrics: false));
      break;
    case TrustLevel.compromised:
      // For a banking app — deny silently with a generic message,
      // also report the signal to the server
      await analytics.logSecurityEvent('device_compromised');
      runApp(const UnsupportedDeviceApp());
      break;
  }
}

