// ── Redacting logs ──────────────────────────────────
class SafeLogger {
  static const _redactKeys = {'password', 'token', 'access_token', 'refresh_token', 'authorization', 'cookie'};
  static String redact(Map<String, dynamic> body) =>
      jsonEncode({
        for (final e in body.entries)
          e.key: _redactKeys.contains(e.key.toLowerCase()) ? '••redacted••' : e.value,
      });
}

Dio buildDio() {
  final dio = Dio();
  dio.interceptors.add(InterceptorsWrapper(
    onRequest: (req, handler) {
      // ✅ Strip Authorization before logging
      final loggable = Map.of(req.headers.map)..remove('authorization');
      log('→ ${req.method} ${req.path} headers=$loggable');
      handler.next(req);
    },
  ));
  return dio;
}

