class _AppLifecycleObserver with WidgetsBindingObserver {
  OverlayEntry? _veil;
  @override void didChangeAppLifecycleState(AppLifecycleState s) {
    if (s == AppLifecycleState.inactive) _show();
    if (s == AppLifecycleState.resumed)  _hide();
  }
  void _show() { _veil = OverlayEntry(builder: (_) => const _Blur()); /* insert into Overlay */ }
  void _hide() { _veil?.remove(); _veil = null; }
}

