Future<void> copySecretBriefly(String secret) async {
  await Clipboard.setData(ClipboardData(text: secret));
  // Clear after 30s so it doesn't sit in the OS clipboard
  Future.delayed(const Duration(seconds: 30), () async {
    final cur = await Clipboard.getData('text/plain');
    if (cur?.text == secret) Clipboard.setData(const ClipboardData(text: ''));
  });
}

