import 'dart:async';
import 'package:dio/dio.dart';
import 'package:flutter_secure_storage/flutter_secure_storage.dart';
import 'package:synchronized/synchronized.dart';

class AuthInterceptor extends Interceptor {
  AuthInterceptor(this._dio, this._storage);
  final Dio _dio;
  final FlutterSecureStorage _storage;
  final _lock = Lock();
  Future<Tokens?>? _inflight;

  @override
  Future<void> onRequest(RequestOptions options, RequestInterceptorHandler h) async {
    final access = await _storage.read(key: 'access');
    if (access != null) options.headers['Authorization'] = 'Bearer $access';
    h.next(options);
  }

  @override
  Future<void> onError(DioException err, ErrorInterceptorHandler h) async {
    if (err.response?.statusCode != 401) return h.next(err);

    // Single-flight: ensure only one refresh runs at a time
    final tokens = await _lock.synchronized<Tokens?>(() async {
      _inflight ??= _refresh();
      try { return await _inflight; } finally { _inflight = null; }
    });

    if (tokens == null) {
      // Refresh failed — wipe & force re-auth
      await _storage.deleteAll();
      AppNavigator.toLogin();
      return h.next(err);
    }

    // Replay the original request with the new token
    final original = err.requestOptions;
    original.headers['Authorization'] = 'Bearer ${tokens.access}';
    final retry = await _dio.fetch(original);
    h.resolve(retry);
  }

  Future<Tokens?> _refresh() async {
    final refresh = await _storage.read(key: 'refresh');
    if (refresh == null) return null;
    try {
      final res = await _dio.post(
        '/auth/refresh',
        data: {'refresh_token': refresh},
        options: Options(headers: {'Authorization': null}), // don't loop
      );
      final access  = res.data['access_token']  as String;
      final newRefr = res.data['refresh_token'] as String;
      // ✅ Atomic-ish write — both keys updated together
      await Future.wait([
        _storage.write(key: 'access',  value: access),
        _storage.write(key: 'refresh', value: newRefr),
      ]);
      return Tokens(access: access, refresh: newRefr);
    } on DioException {
      return null;
    }
  }
}

import 'package:webview_flutter/webview_flutter.dart';

// ✅ Constrained WebView — explicit allowlist, no JS bridge unless needed
class HelpCenterPage extends StatefulWidget {
  const HelpCenterPage({super.key});
  @override State<HelpCenterPage> createState() => _HelpCenterPageState();
}

class _HelpCenterPageState extends State<HelpCenterPage> {
  static const _allowedHosts = {'help.example.com', 'cdn.example.com'};

  late final WebViewController _wv = WebViewController()
    ..setJavaScriptMode(JavaScriptMode.unrestricted)
    ..setBackgroundColor(Colors.white)
    ..setNavigationDelegate(NavigationDelegate(
      onNavigationRequest: (req) {
        final host = Uri.parse(req.url).host;
        return _allowedHosts.contains(host)
            ? NavigationDecision.navigate
            : NavigationDecision.prevent;       // ✅ block off-domain redirects
      },
    ))
    ..loadRequest(Uri.parse('https://help.example.com/start'));

  @override Widget build(_) => Scaffold(body: WebViewWidget(controller: _wv));
}

// ── If you really need a JS channel ────────────────
_wv.addJavaScriptChannel('AppApi', onMessageReceived: (msg) {
  // Validate the message strictly — never eval-style trust
  final parsed = jsonDecode(msg.message) as Map<String, dynamic>;
  if (parsed['op'] == 'requestSupportContact') {
    showSupportSheet();
  }
  // ❌ Don't expose: 'readSecureStorage', 'getDeviceId', 'launchUrl' — opens up exfiltration
});

